SELECT
DATE_FORMAT(statistics_date, '%Y-%m-%d') as date,
count as count
FROM statistics
WHERE statistics_type = #{statisticsType}

    AND api_type = #{apiType}

AND statistics_date BETWEEN #{startDate} AND #{endDate}
ORDER BY statistics_date ASC

SELECT
DATE_FORMAT(statistics_date, '%Y-%m-%d') as date,
SUM(count) as count
FROM statistics
WHERE statistics_type = #{statisticsType}

    AND api_type = #{apiType}

AND statistics_date BETWEEN #{startDate} AND #{endDate}
GROUP BY DATE_FORMAT(statistics_date, '%Y-%m-%d')
ORDER BY DATE_FORMAT(statistics_date, '%Y-%m-%d') ASC
